module.render:
const palette = ['#3b82f6', '#ef4444', '#22c55e', '#f59e0b', '#8b5cf6', '#06b6d4', '#ec4899'];
const secs = sections.map((s) => (s || '').trim()).filter(Boolean);
if (!secs.length) return `<div>(mindmap: first section = center, then branches)</div>`;
const center = secs[0];
const branches = secs.slice(1).map((s, i) => {
  const nl = s.indexOf('\n');
  return {
    title: nl >= 0 ? s.slice(0, nl).trim() : s,
    kids: nl >= 0 ? s.slice(nl + 1).split('\n').map((l) => l.replace(/^-\s+/, '').trim()).filter(Boolean) : [],
    color: args.color || palette[i % palette.length],
  };
});
const side = (list) => list.map((b) => {
  let kids = '';
  b.kids.forEach((k) => { kids += `<div class="mdp-mm-kid">\n\n${k}\n\n</div>`; });
  return `<div class="mdp-mm-branch" style="--mm-c:${b.color};"><div class="mdp-mm-title">\n\n${b.title}\n\n</div>` +
    (kids ? `<div class="mdp-mm-kids">${kids}</div>` : '') + `</div>`;
}).join('');
const layout = args.layout || 'alternate';
let right, left;
if (layout === 'right') { right = branches; left = []; }
else if (layout === 'left') { left = branches; right = []; }
else { right = branches.filter((_, i) => i % 2 === 0); left = branches.filter((_, i) => i % 2 === 1); }
let cstyle = '';
const gap = args.gap && String(args.gap).trim();
const centerC = args.centerColor && String(args.centerColor).trim();
const sc = parseFloat(args.scale);
if (gap) cstyle += `gap:${gap};`;
if (centerC) cstyle += `--mm-center-c:${centerC};`;
if (Number.isFinite(sc) && sc !== 1) cstyle += `font-size:${sc}em;`;
return `\n\n<div class="mdp-mod-mindmap"${cstyle ? ` style="${cstyle}"` : ''}>` +
  `<div class="mdp-mm-side mdp-mm-left">${side(left)}</div>` +
  `<div class="mdp-mm-center">\n\n${center}\n\n</div>` +
  `<div class="mdp-mm-side mdp-mm-right">${side(right)}</div>` +
  `</div>\n\n`;
